namespace sv_2581b91d1e094b32a7901d403d605705.Services;

/// <summary>
/// Scoped service that holds the currently selected warehouse for a single circuit.
/// Fires <see cref="OnChange"/> so any subscribing component can re-render.
/// Scoped lifetime ensures each user/circuit gets its own independent instance.
/// </summary>
public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new("wh-1", "Warehouse A – East"),
        new("wh-2", "Warehouse B – West"),
        new("wh-3", "Warehouse C – Central"),
    ];

    private string _selectedId = AvailableWarehouses[0].Id;

    public string SelectedId => _selectedId;

    public string SelectedName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _selectedId)?.Name ?? _selectedId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_selectedId == warehouseId) return;
        _selectedId = warehouseId;
        OnChange?.Invoke();
    }
}

public record WarehouseInfo(string Id, string Name);

