namespace sv_2581b91d1e094b32a7901d403d605705.Services;

/// <summary>
/// Scoped service that simulates querying low-stock items for a warehouse and
/// broadcasts results to all subscribed components via <see cref="OnAlertCountChanged"/>.
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly Random _random = new();
    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private int _subscriberCount;
    private int _lastCount;

    public int LastCount => _lastCount;

    /// <summary>
    /// Fired whenever a new alert count is available.
    /// All subscribers (dashboard, sidebar badge, etc.) receive the update.
    /// </summary>
    public event Action<int>? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query — returns a random count between 0 and 15.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Call when a component becomes visible and wants polling to run.
    /// Polling starts on the first subscriber and stops when the last unsubscribes.
    /// </summary>
    public void StartPolling(string warehouseId, Func<string> getWarehouseId)
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _cts = new CancellationTokenSource();
            _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
            _ = PollLoopAsync(getWarehouseId, _cts.Token);
        }
    }

    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _cts?.Cancel();
            _timer?.Dispose();
            _timer = null;
            _cts?.Dispose();
            _cts = null;
        }
    }

    /// <summary>
    /// Immediately fetch and broadcast a new count (e.g. after warehouse switch).
    /// </summary>
    public async Task RefreshNowAsync(string warehouseId)
    {
        _lastCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke(_lastCount);
    }

    private async Task PollLoopAsync(Func<string> getWarehouseId, CancellationToken ct)
    {
        // Fire immediately on first subscribe
        await RefreshNowAsync(getWarehouseId());

        try
        {
            while (_timer is not null && await _timer.WaitForNextTickAsync(ct))
            {
                _lastCount = await GetLowStockCountAsync(getWarehouseId());
                OnAlertCountChanged?.Invoke(_lastCount);
            }
        }
        catch (OperationCanceledException) { }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _timer?.Dispose();
        _cts?.Dispose();
    }
}

