@using sv_2581b91d1e094b32a7901d403d605705.Services
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

<div class="d-flex align-items-center gap-2">
    <label class="form-label mb-0 text-nowrap fw-semibold" for="warehouse-select">Warehouse:</label>
    <select id="warehouse-select"
            class="form-select form-select-sm"
            style="width: auto;"
            value="@Warehouse.SelectedId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString();
        if (!string.IsNullOrEmpty(newId))
        {
            Warehouse.SetWarehouse(newId);
        }
    }

    // Re-render this component if something else changes the warehouse
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        Warehouse.OnChange += _handler;
    }

    public void Dispose() => Warehouse.OnChange -= _handler;
}

