@page "/dashboard"
@rendermode InteractiveServer
@using sv_2581b91d1e094b32a7901d403d605705.Services
@using sv_2581b91d1e094b32a7901d403d605705.Components.Shared
@inject WarehouseState Warehouse
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard – @Warehouse.SelectedName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Currently viewing: <strong>@Warehouse.SelectedName</strong></p>

<div class="row g-4 mt-2">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title text-danger">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold text-danger">@_alertCount</p>
                <p class="text-muted mb-0">items below minimum level</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Selected Warehouse</h5>
                <p class="display-6 fw-bold">@Warehouse.SelectedName</p>
                <p class="text-muted mb-0">ID: @Warehouse.SelectedId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6 fw-bold text-success">Active</p>
                <p class="text-muted mb-0">refreshes every 10 seconds</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int _alertCount;
    private Action<int>? _alertHandler;
    private Action? _warehouseHandler;

    protected override void OnInitialized()
    {
        // Subscribe to alert count updates
        _alertHandler = count => InvokeAsync(() =>
        {
            _alertCount = count;
            StateHasChanged();
        });
        AlertService.OnAlertCountChanged += _alertHandler;

        // Subscribe to warehouse changes so the page refreshes immediately
        _warehouseHandler = async () => await InvokeAsync(async () =>
        {
            await AlertService.RefreshNowAsync(Warehouse.SelectedId);
            StateHasChanged();
        });
        Warehouse.OnChange += _warehouseHandler;

        // Start polling while this page is visible
        AlertService.StartPolling(Warehouse.SelectedId, () => Warehouse.SelectedId);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= _alertHandler;
        Warehouse.OnChange -= _warehouseHandler;
        AlertService.StopPolling();
    }
}

